import{_ as a,o as l,c as o,ae as c}from"./chunks/framework.C7FLYIpo.js";const u=JSON.parse('{"title":"스킬 (macOS)","description":"macOS 스킬 설정 UI 및 게이트웨이 지원 상태","frontmatter":{"title":"스킬 (macOS)","description":"macOS 스킬 설정 UI 및 게이트웨이 지원 상태"},"headers":[],"relativePath":"platforms/mac/skills.md","filePath":"platforms/mac/skills.md","lastUpdated":null}'),d={name:"platforms/mac/skills.md"};function i(t,e,s,r,n,m){return l(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="스킬-macos" tabindex="-1">스킬 (macOS) <a class="header-anchor" href="#스킬-macos" aria-label="Permalink to &quot;스킬 (macOS)&quot;">​</a></h1><p>macOS 앱은 게이트웨이를 통해 OpenClaw 스킬을 표시합니다. 로컬에서 스킬을 파싱하지 않습니다.</p><h2 id="데이터-소스" tabindex="-1">데이터 소스 <a class="header-anchor" href="#데이터-소스" aria-label="Permalink to &quot;데이터 소스&quot;">​</a></h2><ul><li><code>skills.status</code> (게이트웨이)는 모든 스킬과 자격 및 누락된 요구 사항을 반환합니다 (번들 스킬에 대한 허용 목록 차단 포함).</li><li>요구 사항은 각 <code>SKILL.md</code>의 <code>metadata.openclaw.requires</code>에서 파생됩니다.</li></ul><h2 id="설치-작업" tabindex="-1">설치 작업 <a class="header-anchor" href="#설치-작업" aria-label="Permalink to &quot;설치 작업&quot;">​</a></h2><ul><li><code>metadata.openclaw.install</code>은 설치 옵션 (brew/node/go/uv)을 정의합니다.</li><li>앱은 <code>skills.install</code>을 호출하여 게이트웨이 호스트에서 설치 프로그램을 실행합니다.</li><li>내장된 위험한 코드 <code>critical</code> 발견은 기본적으로 <code>skills.install</code>을 차단합니다. 의심스러운 발견은 여전히 경고만 합니다. 위험한 재정의는 게이트웨이 요청에 있지만 기본 앱 흐름은 실패 시 안전하게 유지됩니다.</li><li>모든 설치 옵션이 <code>download</code>인 경우 게이트웨이는 모든 다운로드 선택을 표시합니다.</li><li>그렇지 않으면 게이트웨이는 현재 설치 기본 설정과 호스트 바이너리를 사용하여 하나의 선호하는 설치 프로그램을 선택합니다: <code>skills.install.preferBrew</code>가 활성화되어 있고 <code>brew</code>가 있으면 Homebrew를 먼저 사용하고, 그 다음 <code>uv</code>, 그 다음 <code>skills.install.nodeManager</code>에서 구성된 노드 관리자, 그 다음 <code>go</code> 또는 <code>download</code>와 같은 대체.</li><li>노드 설치 레이블은 <code>yarn</code>을 포함하여 구성된 노드 관리자를 반영합니다.</li></ul><h2 id="환경-api-키" tabindex="-1">환경/API 키 <a class="header-anchor" href="#환경-api-키" aria-label="Permalink to &quot;환경/API 키&quot;">​</a></h2><ul><li>앱은 <code>skills.entries.&amp;lt;skillKey&amp;gt;</code> 아래 <code>~/.openclaw/openclaw.json</code>에 키를 저장합니다.</li><li><code>skills.update</code>는 <code>enabled</code>, <code>apiKey</code>, <code>env</code>를 패치합니다.</li></ul><h2 id="원격-모드" tabindex="-1">원격 모드 <a class="header-anchor" href="#원격-모드" aria-label="Permalink to &quot;원격 모드&quot;">​</a></h2><ul><li>설치 + 구성 업데이트는 게이트웨이 호스트에서 발생합니다 (로컬 Mac이 아님).</li></ul>',10)])])}const h=a(d,[["render",i]]);export{u as __pageData,h as default};
